29: /**
30:  * This class encapsulates the invocation of the callback methods defined in the {@link StreamsRebalanceListener}
31:  * interface. When streams group task assignment changes, these methods are invoked. This class wraps those
32:  * callback calls with some logging and error handling.
33:  */
34: public class StreamsRebalanceListenerInvoker {
35: 
36:     private final Logger log;
37: 
38:     private final StreamsRebalanceData streamsRebalanceData;
39:     private Optional<StreamsRebalanceListener> listener;
40: 
41:     StreamsRebalanceListenerInvoker(LogContext logContext, StreamsRebalanceData streamsRebalanceData) {
42:         this.log = logContext.logger(getClass());
43:         this.listener = Optional.empty();
44:         this.streamsRebalanceData = streamsRebalanceData;
45:     }
46: 
47:     public void setRebalanceListener(StreamsRebalanceListener streamsRebalanceListener) {
48:         Objects.requireNonNull(streamsRebalanceListener, "StreamsRebalanceListener cannot be null");
49:         this.listener = Optional.of(streamsRebalanceListener);
50:     }
51: 
52:     public Exception invokeAllTasksRevoked() {
53:         if (listener.isEmpty()) {
54:             return null;
55:         }
56:         return invokeTasksRevoked(streamsRebalanceData.reconciledAssignment().activeTasks());
57:     }
58: 
59:     public Exception invokeTasksAssigned(final StreamsRebalanceData.Assignment assignment) {
60:         if (listener.isEmpty()) {
61:             return null;
62:         }
63:         log.info("Invoking tasks assigned callback for new assignment: {}", assignment);
64:         try {
65:             listener.get().onTasksAssigned(assignment);
66:         } catch (WakeupException | InterruptException e) {
67:             throw e;
68:         } catch (Exception e) {
69:             log.error(
70:                 "Streams rebalance listener failed on invocation of onTasksAssigned for tasks {}",
71:                 assignment,
72:                 e
73:             );
74:             return e;
75:         }
76:         return null;
77:     }
78: 
79:     public Exception invokeTasksRevoked(final Set<StreamsRebalanceData.TaskId> tasks) {
80:         if (listener.isEmpty()) {
81:             return null;
82:         }
83:         log.info("Invoking task revoked callback for revoked active tasks {}", tasks);
84:         try {
85:             listener.get().onTasksRevoked(tasks);
86:         } catch (WakeupException | InterruptException e) {
87:             throw e;
88:         } catch (Exception e) {
89:             log.error(
90:                 "Streams rebalance listener failed on invocation of onTasksRevoked for tasks {}",
91:                 tasks,
92:                 e
93:             );
94:             return e;
95:         }
96:         return null;
97:     }
98: 
99:     public Exception invokeAllTasksLost() {
100:         if (listener.isEmpty()) {
101:             return null;
102:         }
103:         log.info("Invoking tasks lost callback for all tasks");
104:         try {
105:             listener.get().onAllTasksLost();
106:         } catch (WakeupException | InterruptException e) {
107:             throw e;
108:         } catch (Exception e) {
109:             log.error(
110:                 "Streams rebalance listener failed on invocation of onTasksLost.",
111:                 e
112:             );
113:             return e;
114:         }
115:         return null;
